class Solution:
  def is_ref_name_valid(self, ref_name: str) -> bool:
    if not ref_name or not isinstance(ref_name, str):
      return False
    if len(ref_name) > 60:
      return False
    if ref_name.startswith("-") or ref_name.endswith("-") or "--" in ref_name:
      return False
    return True

# Driver code
if __name__ == '__main__':
  s = Solution()
  print(s.is_ref_name_valid('/refs/heads/master'))  # true
  print(s.is_ref_name_valid('-refs/heads/master'))  # false
  print(s.is_ref_name_valid('refs/heads/-master'))  # false
  print(s.is_ref_name_valid('refs/heads/master-'))  # true
  print(s.is_ref_name_valid('refs/heads/master--'))  # false
  print(s.is_ref_name_valid(''))  # false
  print(s.is_ref_name_valid(None))  # false
